    43→type AppointmentWithExtras = Appointment & {
    44→  clientName?: string;
    45→  serviceName?: string;
    46→  professionalName?: string;
    47→  isOnlineBooking?: boolean;
    48→};
    49→
    50→const mapAppointmentStatusToEventStatus = (
    51→  status: AppointmentStatus,
    52→  paymentStatus?: string
    53→): EventStatus => {
    54→  // PRIORIDADE: Se paymentStatus é "paid", sempre retornar "Pago"
    55→  // independente do status do agendamento
    56→  if (paymentStatus === "paid") {
    57→    return "Pago";
    58→  }
    59→
    60→  const statusMap: Record<AppointmentStatus, EventStatus> = {
    61→    [AppointmentStatus.SCHEDULED]: "Agendado",
    62→    [AppointmentStatus.CONFIRMED]: "Agendado",
    63→    [AppointmentStatus.IN_PROGRESS]: "Atendendo",
    64→    [AppointmentStatus.COMPLETED]: "Pgto Pendente",
    65→    [AppointmentStatus.PAID]: "Pago",
    66→    [AppointmentStatus.CANCELLED]: "Cancelado",
    67→    [AppointmentStatus.NO_SHOW]: "Cancelado",
    68→  };
    69→
    70→  return statusMap[status] || "Agendado";
    71→};
    72→
    73→const transformAppointmentToEvent = (
    74→  appointment: AppointmentWithExtras
    75→): CalendarEvent => {
    76→  // Obter os nomes reais do cliente e serviço
    77→  const rawClientName = appointment.clientName || appointment.client?.name;
    78→  const rawServiceName = appointment.serviceName || appointment.service?.name;
    79→
    80→
    81→  // Detectar se é uma reserva (quando ambos são null, undefined, string vazia, ou "Unknown")
    82→  // Reservas são bloqueios feitos pelo profissional sem cliente/serviço definido
    83→  const isReserva =
    84→    (!rawClientName || rawClientName === "Unknown") &&
    85→    (!rawServiceName || rawServiceName === "Unknown");
    86→
    87→  // Definir nomes de exibição com fallbacks apropriados
    88→  // Para reservas, usar texto especial
    89→  const clientName = isReserva ? "Reserva feita pelo profissional" : (rawClientName || "Cliente não definido");
    90→  const serviceName = isReserva ? "" : (rawServiceName || "Serviço não definido");
    91→  const professionalId = appointment.professionalId;
    92→
    93→  // Verifica se é um agendamento online pelo campo source
    94→  const isOnlineBooking = appointment.source === 'online';
    95→
    96→  return {
    97→    id: appointment.id,
    98→    clientName,
    99→    serviceName,
   100→    professionalId,
   101→    start:
   102→      typeof appointment.startTime === "string"
   103→        ? appointment.startTime
   104→        : appointment.startTime.toISOString(),
   105→    end:
   106→      typeof appointment.endTime === "string"
   107→        ? appointment.endTime
   108→        : appointment.endTime.toISOString(),
   109→    status: mapAppointmentStatusToEventStatus(appointment.status, appointment.paymentStatus),
   110→    variant: isReserva ? "reserva" : (isOnlineBooking ? "online" : "default"),
   111→    price: appointment.service?.price || appointment.price,
   112→    isOnlineBooking,
   113→    source: appointment.source,
   114→    rawData: appointment,
   115→  };
   116→};
