   118→const transformAbsenceToBreak = (
   119→  absence: Absence
   120→): {
   121→  id: string;
   122→  start: string;
   123→  end: string;
   124→  type: "ausencia" | "indisponibilidade";
   125→  reason?: string;
   126→} => {
   127→  return {
   128→    id: absence.id,
   129→    start: absence.startDate,
   130→    end: absence.endDate,
   131→    type: "ausencia",
   132→    reason: absence.reason,
