   259→
   260→  // Modal states
   261→  const [modalNovoAgendamento, setModalNovoAgendamento] = useState(false);
   262→  const [modalKey, setModalKey] = useState(0);
   263→  const [modalEditarAgendamento, setModalEditarAgendamento] = useState(false);
   264→  const [modalNovaAusencia, setModalNovaAusencia] = useState(false);
   265→  const [modalComanda, setModalComanda] = useState(false);
   266→  const [selectedAppointment, setSelectedAppointment] =
   267→    useState<Appointment | null>(null);
   268→  const [selectedProfessionalId, setSelectedProfessionalId] =
   269→    useState<string>("");
   270→  const [selectedTime, setSelectedTime] = useState<string>("");
   271→  const [isEditingAbsence, setIsEditingAbsence] = useState(false);
