   273→  const [selectedAbsenceEndTime, setSelectedAbsenceEndTime] = useState<string>("");
   274→  const [selectedAbsenceReason, setSelectedAbsenceReason] = useState<string>("");
   275→  const [initialClientId, setInitialClientId] = useState<string>("");
   276→  const [showFirstAppointmentModal, setShowFirstAppointmentModal] = useState(false);
   277→  const [testClientOnboarding, setTestClientOnboarding] = useState<{ id: string; name: string; phone: string } | null>(null);
   278→  const [professionalIdOnboarding, setProfessionalIdOnboarding] = useState<string | null>(null);
   279→  const [calendarDrawerOpen, setCalendarDrawerOpen] = useState(false);
   280→  const [focusAppointment, setFocusAppointment] = useState<{ id: string; time: string; professionalId: string } | null>(null);
   281→  const [isFirstOnboardingAppointment, setIsFirstOnboardingAppointment] = useState(false);
   282→
   283→  // Comanda modal data
   284→  type ComandaService = {
   285→    id: string;
