   290→    price: number;
   291→    status: "Agendado" | "Atendendo" | "Pgto Pendente" | "Pago" | "Cancelado";
   292→  };
   293→
   294→  type ComandaData = {
   295→    clientName: string;
   296→    date: string;
   297→    services: ComandaService[];
