   300→  const [comandaData, setComandaData] = useState<ComandaData>({
   301→    clientName: "",
   302→    date: "",
   303→    services: [],
   304→  });
   305→
   306→  const dateString = format(selectedDate, "yyyy-MM-dd");
   307→  const isSelectedToday = dateString === format(new Date(), "yyyy-MM-dd");
   308→
   309→  const { appointments, refresh: refreshAppointments } = useRealtimeAppointments({
   310→    date: selectedDate,
