   327→      
   328→      // Setar o foco
   329→      setFocusAppointment(appointment);
   330→      
   331→      // Consumir o flag
   332→      setIsFirstOnboardingAppointment(false);
   333→    }
   334→  };
   335→
   336→
   337→  useWowMoment({
   338→    setSelectedDate,
   339→    refreshAppointments,
   340→  });
   341→
   342→  const { absences, refresh: refreshAbsences } = useRealtimeAbsences({
   343→    date: selectedDate,
   344→  });
   345→
   346→  // Next Appointment Date Logic
   347→  useEffect(() => {
   348→    const fetchNextAppointment = async () => {
   349→      if (!selectedSalon?.id) return;
   350→      try {
   351→        // Get start of today in ISO format to include appointments that started earlier today
   352→        const startOfToday = new Date();
   353→        startOfToday.setHours(0, 0, 0, 0);
   354→
   355→        const response = await appointmentService.list({
   356→          startDate: startOfToday.toISOString(),
   357→          limit: 20,
   358→          sortBy: "startTime",
   359→          sortOrder: "ASC",
   360→        });
   361→
   362→        if (response.data && response.data.length > 0) {
   363→          const validApt = response.data.find(
   364→            (apt) => apt.status !== "cancelled" && apt.status !== "no_show"
   365→          );
   366→          
   367→          if (validApt) {
   368→            const firstAptDate = new Date(validApt.startTime);
   369→            
   370→            // Se estivermos na data padrão (hoje), e houver um agendamento futuro (ou hoje), pular para ele
   371→            // Pular apenas se a data for diferente do hoje absoluto para evitar loops, 
   372→            // e se a data selecionada ainda for o "hoje" inicial.
   373→            const today = new Date();
   374→            if (firstAptDate.toDateString() !== today.toDateString() && 
   375→                selectedDate.toDateString() === today.toDateString()) {
   376→              setSelectedDate(firstAptDate);
   377→            }
   378→          }
   379→        }
   380→      } catch (error) {
   381→        console.error("Error fetching next appointment:", error);
   382→      }
   383→    };
   384→
   385→    fetchNextAppointment();
   386→  }, [selectedSalon?.id]);
   387→
   388→  // Extract timezone into dedicated memo for reactivity
   389→  const salonTimezone = useMemo(
   390→    () => selectedSalon?.timezone || "America/Sao_Paulo",
   391→    [selectedSalon?.timezone]
   392→  );
   393→
   394→  useEffect(() => {
   395→    const loadSalonData = async (): Promise<void> => {
   396→      if (!selectedSalon?.id) return;
   397→
   398→      // STRICT CHECK: Ensure the selectedSalon matches the persisted one to avoid race conditions
   399→      // This prevents the "old" salon from being used just before the new one loads
   400→      const storedSalonId = localStorage.getItem("selectedSalonId");
   401→      if (storedSalonId && selectedSalon.id !== storedSalonId) {
   402→        return;
   403→      }
   404→
   405→      setLoading(true);
   406→      try {
   407→        // Load only operating hours and services here - professionals will be loaded by filters
   408→        const [operatingHoursData, servicesResponse] = await Promise.all([
   409→          agendaService.getSalonOperatingHours(selectedSalon.id),
   410→          serviceService.getAll({ salonId: selectedSalon.id, active: true }),
   411→        ]);
   412→
   413→        setOperatingHours(operatingHoursData);
   414→
   415→        // Process services
   416→        let allServices = [];
   417→        if (servicesResponse.customServices || servicesResponse.standardServices) {
   418→          allServices = [
   419→            ...(servicesResponse.customServices || []),
   420→            ...(servicesResponse.standardServices || []),
   421→          ];
   422→        } else if (Array.isArray(servicesResponse)) {
   423→          allServices = servicesResponse;
   424→        }
   425→        setSalonServices(allServices);
   426→      } catch (error) {
   427→        console.error("Error loading salon data:", error);
   428→      } finally {
   429→        setLoading(false);
   430→      }
   431→    };
   432→
   433→    if (selectedSalon?.id) {
   434→      loadSalonData();
   435→    } else {
   436→      setLoading(false);
   437→    }
   438→  }, [selectedSalon?.id]);
   439→
   440→
   441→
   442→  // Calculate operating hours for selected date
   443→  const salonDaySchedule = useMemo(() => {
   444→    if (!operatingHours) {
   445→      return { startHour: 8, endHour: 20, isOpen: true };
   446→    }
   447→
   448→    const dayOfWeek = selectedDate.getDay();
   449→    const daySchedule = operatingHours.openingHours.find(
   450→      (h) => h.dayOfWeek === dayOfWeek
   451→    );
   452→
   453→    if (!daySchedule) {
   454→      return { startHour: 8, endHour: 20, isOpen: false };
   455→    }
   456→
   457→    if (!daySchedule.isOpen) {
   458→      return { startHour: 8, endHour: 20, isOpen: false };
   459→    }
   460→
   461→    const [openHour] = daySchedule.open.split(":").map(Number);
   462→    const [closeHour] = daySchedule.close.split(":").map(Number);
   463→
   464→    return {
   465→      startHour: openHour,
   466→      endHour: closeHour,
   467→      isOpen: true,
   468→    };
   469→  }, [operatingHours, selectedDate]);
   470→
   471→  // Calcular slotMinutes baseado nas configurações do salão e durações dos serviços
   472→  const slotMinutes = useMemo(() => {
   473→    // Obter slotInterval das configurações do salão (padrão: 15)
   474→    const salonSlotInterval = operatingHours?.settings?.slotInterval || 15;
   475→
   476→    // Se não tiver serviços carregados, usar o slotInterval do salão
   477→    if (!salonServices || salonServices.length === 0) {
   478→      return salonSlotInterval;
   479→    }
   480→
   481→    // Verificar se algum serviço tem duração menor que 30 minutos
   482→    const hasShortService = salonServices.some((service) => {
   483→      const duration = typeof service.duration === 'number'
   484→        ? service.duration
   485→        : parseInt(service.duration || '30', 10);
   486→      return duration < 30;
   487→    });
   488→
   489→    // Verificar se algum profissional tem configuração customizada com duração < 30
   490→    const hasProfessionalShortService = filteredProfessionals.some((professional) => {
   491→      // Verificar se algum serviço tem customDuration para este profissional
   492→      return salonServices.some((service) => {
   493→        if (!service.professionals || service.professionals.length === 0) {
   494→          return false;
   495→        }
   496→
   497→        // Buscar configuração customizada do profissional para este serviço
   498→        const professionalConfig = service.professionals.find(
   499→          (p) => p.professionalId === professional.id
   500→        );
   501→
   502→        if (professionalConfig?.customDuration) {
   503→          return professionalConfig.customDuration < 30;
   504→        }
   505→
   506→        return false;
   507→      });
   508→    });
   509→
   510→    // Se algum serviço ou configuração de profissional tiver < 15 minutos, usar slotInterval do salão
   511→    // Caso contrário, otimizar para slots de 15 minutos
   512→    return hasShortService || hasProfessionalShortService ? salonSlotInterval : 15;
   513→  }, [salonServices, filteredProfessionals, operatingHours?.settings?.slotInterval]);
   514→
   515→  // Filter professionals
   516→  const displayedProfessionals = useMemo(() => {
   517→    if (!professionalFilter || professionalFilter.length === 0) {
   518→      return filteredProfessionals;
   519→    }
   520→    return filteredProfessionals.filter((prof) =>
   521→      professionalFilter.includes(prof.id)
   522→    );
   523→  }, [filteredProfessionals, professionalFilter]);
   524→
   525→  const columns: ProfessionalColumn[] = useMemo(() => {
   526→    const selectedDateString = format(selectedDate, "yyyy-MM-dd");
   527→
   528→    return displayedProfessionals.map((prof) => {
   529→      const registeredAbsences = absences
   530→        .filter((absence) => {
   531→          if (absence.userId !== prof.id) return false;
   532→
   533→          // Filter absences by date in salon timezone
   534→          // formatInTimeZone handles the timezone conversion internally
   535→          const absenceStartDate = formatInTimeZone(
   536→            new Date(absence.startDate),
   537→            salonTimezone,
   538→            "yyyy-MM-dd"
   539→          );
   540→          const absenceEndDate = formatInTimeZone(
   541→            new Date(absence.endDate),
   542→            salonTimezone,
   543→            "yyyy-MM-dd"
