   675→  const handleNewAppointment = (args?: { clientId?: string; professionalId?: string }): void => {
   676→    // Define valores padrão quando criar agendamento sem clicar em slot específico
   677→    const today = parseDateTz(new Date(), salonTimezone);
   678→    let hour = today.getHours();
   679→    const minutes = today.getMinutes();
   680→
   681→    setSelectedAppointment(null);
   682→    setInitialClientId(args?.clientId || "");
   683→    setSelectedProfessionalId(args?.professionalId || "");
   684→
   685→    const endHour = salonDaySchedule.endHour;
   686→    const startHour = salonDaySchedule.startHour;
   687→
   688→    // Regras de arredondamento:
   689→    // ... (rest of rounding logic)
   690→    let defaultMinutes: string;
   691→
   692→    if (minutes < 15) {
   693→      defaultMinutes = "00";
   694→    } else if (minutes < 30) {
   695→      defaultMinutes = "30";
   696→    } else if (minutes < 45) {
   697→      hour = hour + 1;
   698→      defaultMinutes = "00";
   699→    } else {
   700→      hour = hour + 1;
   701→      defaultMinutes = "30";
   702→    }
   703→
   704→    if (hour < startHour) {
   705→      hour = startHour;
   706→      defaultMinutes = "00";
   707→    } else if (hour > endHour) {
   708→      hour = endHour;
   709→      defaultMinutes = "00";
   710→    } else if (hour === endHour) {
   711→      defaultMinutes = "00";
   712→    }
   713→
   714→    const defaultTime = `${hour}:${defaultMinutes}`;
   715→
   716→    setSelectedTime(defaultTime);
   717→    setSelectedProfessionalId(""); // Empty when clicking "Novo Agendamento" button
   718→    
   719→    if (args?.clientId) {
   720→      setInitialClientId(args.clientId);
   721→    } else {
   722→      setInitialClientId("");
   723→    }
   724→    
   725→    setModalKey((prev) => prev + 1); // Forçar remount para resetar estado interno do modal
   726→    setModalNovoAgendamento(true);
   727→  };
