    99→// Função de busca inteligente que ignora case, acentos e permite busca parcial
   100→const normalizeString = (str: string): string => {
   101→  return str
   102→    .toLowerCase()
   103→    .normalize("NFD")
   104→    .replace(/[\u0300-\u036f]/g, "") // Remove acentos
   105→    .replace(/[^a-z0-9\s]/g, ""); // Remove caracteres especiais
   106→};
   107→
   108→// Função de busca flexível que funciona com diferentes formatos de texto
   109→const smartSearch = (searchTerm: string, target: string): boolean => {
   110→  if (!searchTerm || !target) return true;
   111→
   112→  const normalizedSearch = normalizeString(searchTerm);
   113→  const normalizedTarget = normalizeString(target);
   114→
   115→  // Busca exata
   116→  if (normalizedTarget.includes(normalizedSearch)) {
   117→    return true;
   118→  }
   119→
   120→  // Busca por palavras separadas (permite buscar "jo si" para encontrar "João Silva")
   121→  const searchWords = normalizedSearch
   122→    .split(/\s+/)
   123→    .filter((word) => word.length > 0);
   124→  return searchWords.every((word) => normalizedTarget.includes(word));
   125→};
