   612→  const generateTimeSlots = (
   613→    startHour: string,
   614→    endHour: string,
   615→    interval: number = 15
   616→  ): string[] => {
   617→    const slots: string[] = [];
   618→    const [startH, startM] = startHour.split(":").map(Number);
   619→    const [endH, endM] = endHour.split(":").map(Number);
   620→
   621→    const startMinutes = startH * 60 + startM;
   622→    const endMinutes = endH * 60 + endM;
   623→
   624→    for (
   625→      let minutes = startMinutes;
   626→      minutes < endMinutes;
   627→      minutes += interval
   628→    ) {
   629→      const hours = Math.floor(minutes / 60);
   630→      const mins = minutes % 60;
   631→      slots.push(
   632→        `${hours.toString().padStart(2, "0")}:${mins
   633→          .toString()
   634→          .padStart(2, "0")}`
   635→      );
   636→    }
   637→
   638→    return slots;
   639→  };
