   381→      try {
   382→        // Use optimized endpoint to get only professionals that offer this service
   383→        const professionalsWithService = await userService.listProfessionalsByService(
   384→          servicoSelecionado
   385→        );
   386→
   387→        if (!active) return;
   388→
   389→        // Map the IDs from the optimized call to the local professional objects
   390→        const allowedIds = new Set(professionalsWithService.map((p: any) => p.id));
   391→        const filtered = profissionais.filter((p) => allowedIds.has(p.id));
   392→
   393→        setProfissionaisFiltrados(filtered);
   394→
   395→        // Clear professional selection if they don't offer the new service
   396→        if (
   397→          profissionalSelecionado && 
   398→          !allowedIds.has(profissionalSelecionado)
   399→        ) {
   400→          setProfissionalSelecionado("");
   401→        }
   402→      } catch (error) {
