   434→          professionalId: profissionalSelecionado,
   435→          serviceId: servicoSelecionado,
   436→          intervalMinutes: 15,
   437→        });
   438→
   439→        // API pode retornar slots ou availableSlots
   440→        const slotsData =
   441→          availability.slots ||
   442→          availability.availableSlots?.map(({ start, end }) => ({
   443→            startTime: start,
   444→            endTime: end,
   445→            available: true,
   446→          })) ||
   447→          [];
   448→
   449→        const salonTimezone = selectedSalon?.timezone || "America/Sao_Paulo";
   450→        const horarios = slotsData.map((slot) => {
   451→          // Converter horário UTC para timezone do salão
