   461→
   462→        setHorariosDisponiveis(horarios);
   463→
   464→        // Se o horário inicial está disponível, mantê-lo selecionado
   465→        const horarioInicialDisponivel = horarios.find(
   466→          ({ slot, available }) => slot === horarioInicio && available
